1551:       filter_manager_.streamInfo().setShouldDrainConnectionUponCompletion(true);
1552:       connection_manager_.stats_.named_.downstream_rq_ws_on_non_ws_route_.inc();
1553:       sendLocalReply(Code::Forbidden, "", nullptr, absl::nullopt,
1554:                      StreamInfo::ResponseCodeDetails::get().UpgradeFailed);
1555:       return;
1556:     }
1557:     // Allow non websocket requests to go through websocket enabled routes.
1558:   }
1559: 
1560:   // Check if tracing is enabled.
1561:   if (connection_manager_tracing_config_.has_value()) {
1562:     traceRequest();
1563:   }
1564: 
1565:   ENVOY_EXECUTION_SCOPE(trackedStream(), active_span_.get());
1566:   if (!connection_manager_.shouldDeferRequestProxyingToNextIoCycle()) {
1567:     filter_manager_.decodeHeaders(*request_headers_, end_stream);
1568:   } else {
1569:     state_.deferred_to_next_io_iteration_ = true;
1570:     state_.deferred_end_stream_ = end_stream;
1571:   }
1572: 
1573:   // Reset it here for both global and overridden cases.
1574:   resetIdleTimer();
1575: }
