1577: void ConnectionManagerImpl::ActiveStream::traceRequest() {
1578:   ASSERT(connection_manager_tracing_config_.has_value());
1579: 
1580:   const Tracing::Decision tracing_decision =
1581:       Tracing::TracerUtility::shouldTraceRequest(filter_manager_.streamInfo());
1582: 
1583:   if (!trace_refresh_after_route_refresh_) {
1584:     ConnectionManagerImpl::chargeTracingStats(tracing_decision.reason,
1585:                                               connection_manager_.config_->tracingStats());
1586:   }
1587: 
1588:   Tracing::HttpTraceContext trace_context(*request_headers_);
1589:   active_span_ = connection_manager_.tracer().startSpan(
1590:       *this, trace_context, filter_manager_.streamInfo(), tracing_decision);
1591: 
1592:   if (!active_span_) {
1593:     return;
1594:   }
1595:   if (hasCachedRoute()) {
1596:     route_decorator_ = cached_route_.value()->decorator();
1597:     route_tracing_ = cached_route_.value()->tracingConfig();
1598:   }
1599:   if (!operationNameFormatter(*connection_manager_tracing_config_, route_tracing_)) {
1600:     // Only set decorator when there is no operation name formatter configured at either
1601:     // the HCM level or the route level.
1602:     setRequestDecorator(*request_headers_);
