2422: void ConnectionManagerImpl::ActiveStream::refreshRouteCluster() {
2423:   // If there is no cached route, or route cache is frozen, or the request headers are not
2424:   // available, then do not refresh the route cluster.
2425:   if (!hasCachedRoute() || routeCacheBlocked() || request_headers_ == nullptr) {
2426:     return;
2427:   }
2428:   if (const auto* entry = (*cached_route_)->routeEntry(); entry != nullptr) {
2429:     // Refresh the cluster if possible.
2430:     entry->refreshRouteCluster(*request_headers_, filter_manager_.streamInfo());
2431: 
2432:     // Refresh the cached cluster info is necessary.
2433:     if (!cached_cluster_info_.has_value() || cached_cluster_info_.value() == nullptr ||
2434:         (*cached_cluster_info_)->name() != entry->clusterName()) {
2435:       auto* cluster =
2436:           connection_manager_.cluster_manager_.getThreadLocalCluster(entry->clusterName());
2437:       cached_cluster_info_ = (nullptr == cluster) ? nullptr : cluster->info();
2438:       filter_manager_.streamInfo().setUpstreamClusterInfo(cached_cluster_info_.value());
2439:     }
2440:   }
2441: }
