2533: bool ConnectionManagerImpl::ActiveStream::onDeferredRequestProcessing() {
2534:   // TODO(yanavlasov): Merge this with the filter manager continueIteration() method
2535:   if (!state_.deferred_to_next_io_iteration_) {
2536:     return false;
2537:   }
2538:   ENVOY_EXECUTION_SCOPE(trackedStream(), active_span_.get());
2539:   state_.deferred_to_next_io_iteration_ = false;
2540:   bool end_stream = state_.deferred_end_stream_ && deferred_data_ == nullptr &&
2541:                     deferred_request_trailers_ == nullptr && deferred_metadata_.empty();
2542:   filter_manager_.decodeHeaders(*request_headers_, end_stream);
2543:   if (end_stream) {
2544:     return true;
2545:   }
2546:   // Send metadata before data, as data may have an associated end_stream.
2547:   while (!deferred_metadata_.empty()) {
2548:     MetadataMapPtr& metadata = deferred_metadata_.front();
2549:     filter_manager_.decodeMetadata(*metadata);
2550:     deferred_metadata_.pop();
2551:   }
2552:   // Filter manager will return early from decodeData and decodeTrailers if
2553:   // request has completed.
2554:   if (deferred_data_ != nullptr) {
2555:     end_stream = state_.deferred_end_stream_ && deferred_request_trailers_ == nullptr;
2556:     filter_manager_.decodeData(*deferred_data_, end_stream);
2557:   }
2558:   if (deferred_request_trailers_ != nullptr) {
2559:     request_trailers_ = std::move(deferred_request_trailers_);
2560:     filter_manager_.decodeTrailers(*request_trailers_);
2561:   }
2562:   return true;
2563: }
